import argparse
from pathlib import Path
import joblib
from typing import List

def load_model(model_path: Path):
    """Load the persisted Pipeline from disk."""
    return joblib.load(model_path)

def predict_sentiment(model, sentences: List[str]):
    """Return a list of predicted labels for the given sentences."""
    return model.predict(sentences)

def main() -> None:
    parser = argparse.ArgumentParser(description="Predict sentiment of a sentence using the trained model.")
    parser.add_argument("sentence", type=str, help="The sentence to classify")
    args = parser.parse_args()

    model_path = Path(__file__).parent / "model.joblib"
    model = load_model(model_path)
    prediction = predict_sentiment(model, [args.sentence])[0]
    print(f"Sentiment: {prediction}")

if __name__ == "__main__":
    main()

